function solve(value: number[], limit: number[]): number {
    const n = value.length;
    const elements: {limit: number, value: number}[] = [];
    for (let i = 0; i < n; i++) {
        elements.push({limit: limit[i], value: value[i]});
    }
    elements.sort((a, b) => a.limit - b.limit);

    const maxHeap: number[] = [];
    let res = 0;
    let currentActive = 0;
    let i = 0;

    while (i < n || maxHeap.length > 0) {
        while (i < n && elements[i].limit <= currentActive) {
            i++;
        }
        if (i < n && (maxHeap.length === 0 || elements[i].limit <= currentActive + (n - i))) {
            const {limit, value} = elements[i];
            const maxPossible = limit - 1;
            if (currentActive < maxPossible) {
                maxHeap.push(-value);
                maxHeap.sort((a, b) => a - b);
                i++;
                continue;
            }
        }
        if (maxHeap.length > 0) {
            res += -maxHeap.shift()!;
            currentActive++;
        } else {
            break;
        }
    }
    return res;
}
